import json
from datetime import datetime

def serialize_datetime_objects(obj):
    if isinstance(obj, datetime):
        return obj.isoformat()
    raise TypeError(f"Object of type {obj.__class__.__name__} is not JSON serializable")

if __name__ == '__main__':
    # Örnek kullanım:
    data = {
        "name": "John Doe",
        "created_at": datetime.now(),
        "event_date": datetime(2023, 10, 27, 14, 30, 0),
        "nested_data": {
            "last_updated": datetime(2023, 1, 1, 10, 0, 0)
        },
        "items": [
            {"id": 1, "purchase_time": datetime(2022, 5, 10, 8, 15, 23)},
            {"id": 2, "shipment_time": datetime(2023, 9, 1, 12, 0, 0)}
        ]
    }

    # Datetime objelerini JSON'a serialize et
    json_output = json.dumps(data, default=serialize_datetime_objects, indent=4)

    print(json_output)

    # Farklı bir örnek, sadece bir datetime objesi
    single_datetime = datetime(2024, 1, 1, 0, 0, 0)
    json_single_output = json.dumps(single_datetime, default=serialize_datetime_objects)
    print(f"\nSadece datetime objesi: {json_single_output}")

    # Hata durumunu göstermek için (serileştirilemeyen bir tür)
    try:
        json.dumps({"a": object()}, default=serialize_datetime_objects)
    except TypeError as e:
        print(f"\nHata örneği: {e}")
